sql_query:
SELECT "Trial phase"
FROM clinical_trials
WHERE "Name of ICI" = 'Ipilimumab';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Trial phase" AS source_value FROM clinical_trials
WHERE "Name of ICI" = 'Ipilimumab'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_phase_bucket(source_value) AS "phase_bucket"
FROM base;
